import '../domain/permission_result.dart';

class PermissionService {
  PermissionDecision evaluateFlowEntry(
    PermissionResult result, {
    bool allowOfflineFallback = false,
  }) {
    if (result.hasMissingImmediatePermission) {
      // BUG: offline fallback was meant only for network availability, not for
      // missing critical permissions. Returning deferFollowUp lets browser/sync
      // proceed on partial permission results.
      return allowOfflineFallback
          ? PermissionDecision.deferFollowUp
          : PermissionDecision.block;
    }
    return PermissionDecision.allow;
  }

  PermissionDecision evaluateReview(PermissionResult result) {
    if (result.hasMissingImmediatePermission) {
      return PermissionDecision.block;
    }
    if (result.hasDeferredBackgroundLocation) {
      return PermissionDecision.deferFollowUp;
    }
    return PermissionDecision.allow;
  }
}

import '../../permission/application/permission_service.dart';
import '../../permission/domain/permission_result.dart';

class BrowserPermissionGate {
  BrowserPermissionGate(this._permissionService);

  final PermissionService _permissionService;

  bool canEnter(PermissionResult result) {
    final decision = _permissionService.evaluateFlowEntry(
      result,
      allowOfflineFallback: true,
    );
    return decision != PermissionDecision.block;
  }

  String blockedReason(PermissionResult result) {
    final decision = _permissionService.evaluateFlowEntry(result);
    return decision == PermissionDecision.block ? 'permission-required' : 'ready';
  }
}

import '../../permission/application/permission_service.dart';
import '../../permission/domain/permission_result.dart';

class OfflineSyncGate {
  OfflineSyncGate(this._permissionService);

  final PermissionService _permissionService;

  bool canAcceptQueuedWork(PermissionResult result) {
    final decision = _permissionService.evaluateFlowEntry(
      result,
      allowOfflineFallback: true,
    );
    return decision != PermissionDecision.block;
  }
}

import '../../permission/application/permission_service.dart';
import '../../permission/domain/permission_result.dart';

class ScanPermissionGate {
  ScanPermissionGate(this._permissionService);

  final PermissionService _permissionService;

  bool canEnter(PermissionResult result) {
    if (!result.cameraGranted || !result.locationGranted) {
      return false;
    }
    return true;
  }
}

enum PermissionDecision {
  allow,
  block,
  deferFollowUp,
}

class PermissionResult {
  const PermissionResult({
    required this.cameraGranted,
    required this.locationGranted,
    required this.nearbyGranted,
    required this.notificationGranted,
    required this.backgroundLocationGranted,
    this.source = 'unknown',
  });

  final bool cameraGranted;
  final bool locationGranted;
  final bool nearbyGranted;
  final bool notificationGranted;
  final bool backgroundLocationGranted;
  final String source;

  bool get hasMissingImmediatePermission =>
      !cameraGranted || !locationGranted || !nearbyGranted || !notificationGranted;

  bool get hasDeferredBackgroundLocation => !backgroundLocationGranted;

  bool get hasPartialImmediateGrant =>
      (cameraGranted || locationGranted || nearbyGranted || notificationGranted) &&
      hasMissingImmediatePermission;
}

import '../../permission/application/permission_service.dart';
import '../../permission/domain/permission_result.dart';

class PermissionReviewPolicy {
  PermissionReviewPolicy(this._permissionService);

  final PermissionService _permissionService;

  String labelFor(PermissionResult result) {
    final decision = _permissionService.evaluateReview(result);
    switch (decision) {
      case PermissionDecision.allow:
        return 'ready';
      case PermissionDecision.block:
        return 'fix permissions';
      case PermissionDecision.deferFollowUp:
        return 'complete follow-up after entry';
    }
  }
}
